import { PaginationItemTypes } from '../types/PaginationItemTypes';
export const createPaginationItem = (item, disabled, page, count, handleClick, buttonPage) => typeof item === 'number' ? {
  onClick: event => handleClick(event, item),
  type: PaginationItemTypes.Page,
  page: item,
  selected: item === page,
  disabled
} : {
  onClick: event => {
    handleClick(event, buttonPage(item, page, count));
  },
  type: item,
  selected: false,
  disabled: disabled || item.indexOf(PaginationItemTypes.Ellipsis) === -1 && (item === PaginationItemTypes.Next || item === PaginationItemTypes.Last ? page >= count : page <= 1)
};
